export function script(input) {
  const secrets = Array.isArray(input.secrets) ? input.secrets : [];
  const analyticsResults = Array.isArray(input.analyticsResults) ? input.analyticsResults : [];
  const repositoryUrl = typeof input.repositoryUrl === 'string' ? input.repositoryUrl.trim() : '';
  const authorizationNotes = typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null;
  function firstText(...values) {
    for (const value of values) {
      if (typeof value === 'string' && value.trim().length > 0) return value.trim();
    }
    return null;
  }
  function sourceData(secret) {
    return secret?.SourceMetadata?.Data || {};
  }
  function gitData(secret) {
    const data = sourceData(secret);
    return data.Git || data.Github || data.Gitlab || data.Filesystem || {};
  }
  function redactedValue(secret) {
    const redacted = firstText(secret?.Redacted, secret?.StructuredData?.redacted, secret?.StructuredData?.Redacted);
    return redacted || '[redacted]';
  }
  const findings = secrets.map((secret) => {
    const source = gitData(secret);
    const detector = firstText(secret?.DetectorName, secret?.DetectorType, 'Unknown secret') || 'Unknown secret';
    return {
      detector,
      detectorType: firstText(secret?.DetectorType, secret?.DecoderName),
      verified: secret?.Verified === true,
      redacted: redactedValue(secret),
      file: firstText(source.file, source.path, secret?.SourceMetadata?.Data?.Filesystem?.file),
      commit: firstText(source.commit, source.commitHash, source.commit_hash),
      repository: firstText(source.repository, source.repo, repositoryUrl),
      email: firstText(source.email, source.authorEmail),
      timestamp: firstText(source.timestamp, source.commitTimestamp, source.date),
      source: firstText(secret?.SourceName, secret?.SourceType)
    };
  }).sort((a, b) => Number(b.verified) - Number(a.verified) || a.detector.localeCompare(b.detector) || String(a.file || '').localeCompare(String(b.file || ''))).slice(0, 100);
  const verifiedFindings = findings.filter((finding) => finding.verified).length;
  const secretCount = Number.isFinite(Number(input.secretCount)) ? Number(input.secretCount) : secrets.length;
  const verifiedCount = Number.isFinite(Number(input.verifiedCount)) ? Number(input.verifiedCount) : verifiedFindings;
  return {
    report: {
      summary: {
        repositoryUrl,
        secretCount,
        verifiedCount,
        hasVerifiedSecrets: input.hasVerifiedSecrets === true || verifiedCount > 0,
        reportedFindings: findings.length
      },
      authorizationNotes,
      findings,
      analyticsResults: analyticsResults.slice(0, 100).map((result) => ({
        scanner: result?.scanner || 'trufflehog',
        severity: result?.severity || 'high',
        finding_hash: result?.finding_hash || null,
        asset_key: result?.asset_key || repositoryUrl,
        detector: result?.DetectorName || result?.DetectorType || null,
        verified: result?.Verified === true,
        redacted: result?.Redacted || '[redacted]'
      })),
      nextSteps: [
        'Immediately rotate any verified exposed credentials before reporting',
        'Confirm repository and commit are in authorized scope',
        'Use redacted evidence only in bug bounty submissions'
      ]
    }
  };
}
